125	// SectionHeader per docs/design.md §6 — kept inline until a second consumer
126	// shows up. The `══════ Label ══════` visual uses horizontal rules bracketing
127	// the title; a single flex row with 2-px borders keeps it token-friendly.
128	function SectionHeader({ title }: { title: string }) {
