144	function bucketFor(status: ApplicationStatus): Segment | null {
145	  if (status === 'withdrawn') return null;
146	  if (status === 'cancelled_listing_edit') return null;
147	  if (status === 'cancelled_listing_closed') return null;
148	  return STATUS_BUCKET[status];
149	}
150	
151	export default function ListerInboxApplications() {
152	  const { user } = useAuth();
153	  const userId = user?.id ?? null;
154	  const { show: showToast } = useToast();
155	
156	  const [segment, setSegment] = useState<Segment>('pending');
157	  const [rows, setRows] = useState<Row[]>([]);
158	  const [loading, setLoading] = useState(true);
159	  const [refreshing, setRefreshing] = useState(false);
160	  const [error, setError] = useState<string | null>(null);
161	
162	  const load = useCallback(async () => {
163	    if (!userId) return;
164	    setError(null);
165	    const { data, error: rpcError } = await supabase.rpc('list_my_applications_as_lister');
166	    if (rpcError) {
167	      setError("Couldn't load applications.");
168	      setRows([]);
169	    } else {
170	      setRows(data ?? []);
171	    }
172	  }, [userId]);
173	
174	  // Mirror `load` through a ref so the realtime effect can call the latest
175	  // closure without re-subscribing every time `load` re-creates. Same
176	  // pattern as the creator realtime handler (Codebase Pattern #82/#106).
177	  const loadRef = useRef(load);
178	  useEffect(() => {
179	    loadRef.current = load;
180	  }, [load]);
181	
182	  // Toast cooldown: two INSERTs arriving in the same second (e.g. a
183	  // creator applying to two listings back-to-back, or two creators
184	  // racing) would otherwise stack back-to-back toasts. The re-fetch
185	  // itself is idempotent — only the user-facing banner needs dedup.
186	  const lastToastAtRef = useRef(0);
187	  const TOAST_COOLDOWN_MS = 3000;
188	
189	  useEffect(() => {
190	    setLoading(true);
191	    void load().finally(() => setLoading(false));
192	  }, [load]);
193	
194	  const onRefresh = useCallback(async () => {
195	    setRefreshing(true);
196	    await load();
197	    setRefreshing(false);
198	  }, [load]);
199	
200	  // Realtime INSERT subscription. No client-side filter: applications has
201	  // no lister_id column to filter on, and `applications_lister_read` RLS is
202	  // the authoritative boundary (the broker drops any row the caller can't
203	  // SELECT). supabase.realtime.setAuth(token) mirrors the US-036 +
204	  // US-044 pattern for authenticated websockets (Codebase Pattern #105).
205	  useEffect(() => {
206	    if (!userId) return;
207	    const token = getCachedToken();
208	    if (!token) return;
209	    let cancelled = false;
210	    let activeChannel: ReturnType<typeof supabase.channel> | null = null;
211	    void supabase.realtime.setAuth(token).then(() => {
212	      if (cancelled) return;
213	      activeChannel = supabase
214	        .channel(`lister-inbox-applications-${userId}`)
215	        .on(
216	          'postgres_changes',
217	          {
218	            event: 'INSERT',
219	            schema: 'public',
220	            table: 'applications',
221	          },
222	          () => {
223	            void loadRef.current();
224	            const now = Date.now();
225	            if (now - lastToastAtRef.current >= TOAST_COOLDOWN_MS) {
226	              lastToastAtRef.current = now;
227	              showToast({
228	                message: 'New application received',
229	                variant: 'info',
230	              });
231	            }
232	          },
233	        )
234	        .subscribe();
235	    });
236	    return () => {
237	      cancelled = true;
238	      if (activeChannel) void supabase.removeChannel(activeChannel);
239	    };
240	  }, [userId, showToast]);
241	
242	  const byBucket = useMemo(() => {
243	    const map: Record<Segment, Row[]> = { pending: [], approved: [], rejected: [] };
244	    for (const r of rows) {
245	      const b = bucketFor(r.status);
246	      if (b) map[b].push(r);
247	    }
248	    return map;
249	  }, [rows]);
250	
251	  const counts = useMemo<Record<Segment, number>>(
252	    () => ({
253	      pending: byBucket.pending.length,
254	      approved: byBucket.approved.length,
255	      rejected: byBucket.rejected.length,
256	    }),
257	    [byBucket],
258	  );
259	
260	  const grouped = useMemo(() => groupByListing(byBucket[segment]), [byBucket, segment]);
261	  const visibleCount = byBucket[segment].length;
262	
263	  return (
264	    <SafeAreaView style={styles.root}>
265	      <ScrollView
266	        contentContainerStyle={styles.scroll}
267	        refreshControl={
268	          <RefreshControl refreshing={refreshing} onRefresh={onRefresh} tintColor={colors.ink} />
269	        }
270	      >
271	        <Text style={[textStyles.display, styles.header]}>Inbox</Text>
272	        <SegmentControl active={segment} counts={counts} onChange={setSegment} />
273	
274	        {loading ? (
275	          <View style={styles.list} testID="applications-loading">
276	            <SkeletonCard />
277	            <SkeletonCard />
278	          </View>
279	        ) : error ? (
280	          <View style={styles.emptyBox}>
281	            <Text style={[textStyles.body, { color: colors.danger }]}>{error}</Text>
282	          </View>
283	        ) : visibleCount === 0 ? (
284	          <View style={styles.emptyBox} testID={`applications-empty-${segment}`}>
285	            <Text style={[textStyles.body, { color: colors.ink70, textAlign: 'center' }]}>
286	              {emptyMessageFor(segment)}
287	            </Text>
288	          </View>
289	        ) : (
290	          <View style={styles.list}>
291	            {grouped.map((group) => (
292	              <View key={group.listingId} style={styles.group}>
293	                <SectionHeader title={group.listingTitle} />
294	                {group.rows.map((row) => (
295	                  <ApplicationInboxRow key={row.application_id} row={row} />
296	                ))}
297	              </View>
298	            ))}
299	          </View>
300	        )}
301	      </ScrollView>
302	    </SafeAreaView>
303	  );
304	}
305	
306	function emptyMessageFor(segment: Segment): string {
307	  switch (segment) {
308	    case 'pending':
309	      return 'No pending applications. New applications will land here in real time.';
310	    case 'approved':
311	      return 'No approvals yet.';
312	    case 'rejected':
313	      return 'No rejections yet.';
314	  }
315	}
316	
317	type ListingGroup = { listingId: string; listingTitle: string; rows: Row[] };
318	
319	function groupByListing(rows: Row[]): ListingGroup[] {
320	  const order: string[] = [];
321	  const by = new Map<string, ListingGroup>();
322	  for (const r of rows) {
323	    let g = by.get(r.listing_id);
324	    if (!g) {
325	      g = { listingId: r.listing_id, listingTitle: r.listing_title, rows: [] };
326	      by.set(r.listing_id, g);
327	      order.push(r.listing_id);
328	    }
329	    g.rows.push(r);
330	  }
331	  return order.map((id) => by.get(id)!);
332	}
333	
334	function ApplicationInboxRow({ row }: { row: Row }) {
335	  const pillStatus: StatusPillStatus =
336	    row.status === 'pending' || row.status === 'approved' || row.status === 'rejected'
337	      ? row.status
338	      : 'cancelled';
339	  const relative = formatRelativeTime(new Date(row.created_at));
340	  const pitch = row.cover_note?.trim() ?? '';
341	
342	  return (
343	    <View
344	      style={[styles.card, shadows.hard]}
345	      accessibilityLabel={`Application from ${row.creator_username}, ${pillStatus}, applied ${relative}`}
346	      testID={`application-${row.application_id}`}
347	    >
348	      <View style={styles.cardTopRow}>
349	        <Text style={[textStyles.h2, { color: colors.ink }]} numberOfLines={1}>
350	          @{row.creator_username}
351	        </Text>
352	        <StatusPill status={pillStatus} />
353	      </View>
354	
355	      <View style={styles.metricsBlock}>
356	        <MetricLine
357	          platform="TikTok"
358	          handle={row.tiktok_handle}
359	          primary={row.tiktok_follower_count}
360	          primaryLabel="followers"
361	          testID={`metrics-tiktok-${row.application_id}`}
362	        />
363	        <MetricLine
364	          platform="Instagram"
365	          handle={row.instagram_handle}
366	          primary={row.instagram_follower_count}
367	          primaryLabel="followers"
368	          secondary={row.instagram_avg_views_last_10}
369	          secondaryLabel="avg views"
370	          testID={`metrics-ig-${row.application_id}`}
371	        />
372	      </View>
373	
374	      {pitch ? (
375	        <Text
376	          style={[textStyles.body, { color: colors.ink70 }]}
377	          numberOfLines={2}
378	          testID={`pitch-${row.application_id}`}
379	        >
380	          {pitch}
381	        </Text>
382	      ) : null}
383	
384	      <Text style={[textStyles.caption, { color: colors.ink70 }]}>Applied {relative}</Text>
385	    </View>
386	  );
387	}
388	
389	type MetricLineProps = {
390	  platform: string;
391	  handle: string | null;
392	  primary: number | null;
393	  primaryLabel: string;
394	  secondary?: number | null;
395	  secondaryLabel?: string;
396	  testID?: string;
397	};
398	
399	function MetricLine({
400	  platform,
401	  handle,
402	  primary,
403	  primaryLabel,
404	  secondary,
405	  secondaryLabel,
406	  testID,
407	}: MetricLineProps) {
408	  if (!handle) {
409	    return (
410	      <View style={styles.metricRow} testID={testID}>
411	        <Text style={[textStyles.caption, { color: colors.ink70, width: 80 }]}>{platform}</Text>
412	        <Text style={[textStyles.caption, { color: colors.ink70 }]}>no handle linked</Text>
413	      </View>
414	    );
415	  }
416	  return (
417	    <View style={styles.metricRow} testID={testID}>
418	      <Text style={[textStyles.caption, { color: colors.ink70, width: 80 }]}>{platform}</Text>
419	      <Text style={styles.metricHandle} allowFontScaling={false} numberOfLines={1}>
420	        @{handle}
421	      </Text>
422	      <Text style={[textStyles.caption, { color: colors.ink }]}>
423	        {formatCount(primary)} {primaryLabel}
424	        {secondary != null && secondaryLabel
425	          ? ` · ${formatCount(secondary)} ${secondaryLabel}`
426	          : ''}
427	      </Text>
428	    </View>
429	  );
430	}
431	
432	// Compact thousands formatter: 12_345 → "12.3K", 1_200_000 → "1.2M". Keeps
433	// inbox rows dense and matches the other social-metric callouts on the
434	// discover + detail screens.
435	function formatCount(n: number | null): string {
436	  if (n == null || n < 0) return '—';
437	  if (n < 1_000) return n.toLocaleString('en-US');
438	  if (n < 1_000_000) return `${(n / 1_000).toFixed(n < 10_000 ? 1 : 0)}K`;
439	  return `${(n / 1_000_000).toFixed(n < 10_000_000 ? 1 : 0)}M`;
440	}
441	
442	const styles = StyleSheet.create({
443	  root: { flex: 1, backgroundColor: colors.canvas },
444	  scroll: {
445	    padding: spacing.base,
446	    gap: spacing.md,
447	    paddingBottom: spacing.xxxl,
448	  },
449	  header: {
450	    color: colors.ink,
451	    marginBottom: spacing.xs,
452	  },
453	  segmentRow: {
454	    flexDirection: 'row',
455	    flexWrap: 'wrap',
456	    gap: spacing.sm,
457	    marginBottom: spacing.xs,
458	  },
459	  segment: {
460	    minHeight: 32,
461	    paddingHorizontal: spacing.md,
462	    paddingVertical: spacing.xs + 2,
463	    borderRadius: radii.pill,
464	    borderWidth: 2,
465	    borderColor: colors.ink,
466	    alignItems: 'center',
467	    justifyContent: 'center',
468	  },
469	  list: {
470	    gap: spacing.lg,
471	  },
472	  group: {
473	    gap: spacing.md,
474	  },
475	  sectionHeaderRow: {
476	    flexDirection: 'row',
477	    alignItems: 'center',
478	    gap: spacing.sm,
479	  },
480	  sectionRule: {
481	    flex: 1,
482	    height: 2,
483	    backgroundColor: colors.ink,
484	  },
485	  card: {
486	    backgroundColor: colors.surface,
487	    borderColor: colors.ink,
488	    borderWidth: 2,
489	    borderRadius: radii.card,
490	    padding: spacing.base,
491	    gap: spacing.sm,
492	  },
493	  cardTopRow: {
494	    flexDirection: 'row',
495	    gap: spacing.sm,
496	    alignItems: 'center',
497	    justifyContent: 'space-between',
498	  },
499	  metricsBlock: {
500	    gap: spacing.xs,
501	  },
502	  metricRow: {
503	    flexDirection: 'row',
504	    alignItems: 'center',
505	    gap: spacing.sm,
506	    flexWrap: 'wrap',
507	  },
508	  metricHandle: {
509	    fontFamily: fontFamilies.mono,
510	    fontSize: 13,
511	    lineHeight: 18,
512	    color: colors.ink,
513	  },
514	  emptyBox: {
515	    padding: spacing.lg,
516	    alignItems: 'center',
517	  },
518	});
