// row-level lock (SELECT ... FOR UPDATE). If the lister's version bump
// interleaves, the RPC sees a different current_version_id and returns
// LISTING_VERSION_CHANGED. This satisfies the §5.5 "re-run eligibility
// against the NOW-current version_id" invariant without duplicating the
// eligibility engine in PL/pgSQL. Spec §5.5 also enumerates
// LISTING_NOT_ACTIVE and ALREADY_APPLIED, both surfaced here.
//
// Fail-closed on missing metrics — inherited from the shared eligibility
// engine (docs/tech-architecture.md §3d): missing creator_profiles row,
// null platform fields, or unknown operators on a PRE condition all
// count as ineligible.

import { createClient } from "npm:@supabase/supabase-js@2";
import { verifyJwt } from "../_shared/jwt.ts";
import { corsHeaders } from "../_shared/cors.ts";
import {
  type ConditionRow,
  type CreatorProfileRow,
  EMPTY_CREATOR_METRICS,
  evaluatePreConditions,
} from "../_shared/eligibility.ts";

const UUID_RE =
  /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

// Hard cap on cover_note — the schema column is `text` (unlimited), but
// anything longer than a few paragraphs is almost certainly abuse or
// accidental paste. 2000 chars = roughly 400 words, plenty for a pitch.
const COVER_NOTE_MAX_LEN = 2000;

interface ApplyRequest {
  listing_id?: unknown;
  cover_note?: unknown;
}

function jsonResponse(status: number, body: unknown): Response {
  return new Response(JSON.stringify(body), {
    status,
    headers: { ...corsHeaders, "Content-Type": "application/json" },
  });
}

function bearerToken(req: Request): string | null {
  const raw = req.headers.get("Authorization") ??
    req.headers.get("authorization");
  if (!raw) return null;
  const m = raw.match(/^Bearer\s+(.+)$/i);
  return m ? m[1].trim() : null;
}

Deno.serve(async (req) => {
  if (req.method === "OPTIONS") {
    return new Response(null, { status: 204, headers: corsHeaders });
  }
  if (req.method !== "POST") {
    return jsonResponse(405, { error: "METHOD_NOT_ALLOWED" });
  }

  const token = bearerToken(req);
  if (!token) return jsonResponse(401, { error: "UNAUTHORIZED" });

  let claims;
  try {
    claims = await verifyJwt(token);
  } catch {
    return jsonResponse(401, { error: "UNAUTHORIZED" });
  }
  if (claims.app_role !== "creator") {
    return jsonResponse(403, { error: "FORBIDDEN" });
  }

  let body: ApplyRequest;
  try {
    body = await req.json();
  } catch {
    return jsonResponse(400, { error: "INVALID_JSON" });
  }

  const listingId =
    typeof body.listing_id === "string" && UUID_RE.test(body.listing_id)
      ? body.listing_id
      : null;
  if (!listingId) {
    return jsonResponse(400, { error: "INVALID_REQUEST" });
  }

  let coverNote: string | null = null;
  if (body.cover_note !== undefined && body.cover_note !== null) {
    if (typeof body.cover_note !== "string") {
      return jsonResponse(400, { error: "INVALID_REQUEST" });
    }
    const trimmed = body.cover_note.trim();
    if (trimmed.length > COVER_NOTE_MAX_LEN) {
      return jsonResponse(400, { error: "INVALID_REQUEST" });
    }
    coverNote = trimmed.length > 0 ? trimmed : null;
  }

  const supabaseUrl = Deno.env.get("SUPABASE_URL");
  const serviceRoleKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");
  if (!supabaseUrl || !serviceRoleKey) {
    return jsonResponse(500, { error: "SERVER_MISCONFIGURED" });
  }

  const supabase = createClient(supabaseUrl, serviceRoleKey, {
    auth: { persistSession: false, autoRefreshToken: false },
  });

  const { data: listing, error: listingError } = await supabase
    .from("listings")
    .select("id,status,current_version_id")
    .eq("id", listingId)
    .maybeSingle();

  if (listingError) {
    console.error("listings lookup failed", listingError);
    return jsonResponse(500, { error: "DB_ERROR" });
  }
  // Draft and archived collapse to 404 to match get-listing-detail's
  // visibility rules — there's nothing to apply to and we don't want to
  // leak id existence.
  if (!listing || listing.status === "draft" || listing.status === "archived") {
    return jsonResponse(404, { error: "LISTING_NOT_FOUND" });
  }
  // Non-active (paused / closed) listings are a 409 per §5.5. They are
  // visible for detail view but not applyable.
  if (listing.status !== "active") {
    return jsonResponse(409, { error: "LISTING_NOT_ACTIVE" });
  }

  const versionId = listing.current_version_id as string | null;
  if (!versionId) {
    console.error("listing missing current_version_id", listing.id);
    return jsonResponse(500, { error: "DB_ERROR" });
  }

  const [conditionsRes, profileRes] = await Promise.all([
    supabase
      .from("listing_conditions")
      .select("*")
      .eq("listing_version_id", versionId),
    supabase
      .from("creator_profiles")
      .select(
        "tiktok_follower_count,tiktok_avg_views_last_10,tiktok_total_likes," +
          "tiktok_video_count,tiktok_is_verified,instagram_follower_count," +
          "instagram_avg_views_last_10,instagram_media_count",
      )
      .eq("user_id", claims.sub)
      .maybeSingle(),
  ]);

  if (conditionsRes.error) {
    console.error("listing_conditions lookup failed", conditionsRes.error);
    return jsonResponse(500, { error: "DB_ERROR" });
  }
  if (profileRes.error) {
    console.error("creator_profiles lookup failed", profileRes.error);
    return jsonResponse(500, { error: "DB_ERROR" });
  }

  const conditions = (conditionsRes.data ?? []) as ConditionRow[];
  const metrics: CreatorProfileRow = profileRes.data ?? EMPTY_CREATOR_METRICS;
  const failed = evaluatePreConditions(conditions, metrics);
  if (failed.length > 0) {
    return jsonResponse(403, {
      error: "INELIGIBLE",
      failed_conditions: failed,
    });
  }

  const { data: rpcData, error: rpcError } = await supabase.rpc(
    "apply_to_listing_rpc",
    {
      p_listing_id: listingId,
      p_creator_id: claims.sub,
      p_expected_version_id: versionId,
      p_cover_note: coverNote,
    },
  );

  if (rpcError) {
    console.error("apply_to_listing_rpc error", rpcError);
    return jsonResponse(500, { error: "DB_ERROR" });
  }

  const result = rpcData as
    | {
      application_id?: string;
      listing_version_id?: string;
      error?: string;
      current_version_id?: string;
    }
    | null;

  if (result?.error === "LISTING_NOT_FOUND") {
    return jsonResponse(404, { error: "LISTING_NOT_FOUND" });
  }
  if (result?.error === "LISTING_NOT_ACTIVE") {
    return jsonResponse(409, { error: "LISTING_NOT_ACTIVE" });
  }
  if (result?.error === "LISTING_VERSION_CHANGED") {
    return jsonResponse(409, {
      error: "LISTING_VERSION_CHANGED",
      current_version_id: result.current_version_id,
    });
  }
  if (result?.error === "ALREADY_APPLIED") {
    return jsonResponse(409, { error: "ALREADY_APPLIED" });
  }

  if (!result?.application_id || !result.listing_version_id) {
    console.error("apply_to_listing_rpc returned unexpected shape", result);
    return jsonResponse(500, { error: "DB_ERROR" });
  }

  return jsonResponse(200, {
    application_id: result.application_id,
    listing_version_id: result.listing_version_id,
  });
});
"},{"name":"functions/_shared/jwt.ts","content":"// Custom JWT helper for Marketify edge functions.
//
// Contract: signJwt({ sub, app_role, session_id }, { ttlSeconds? }) -> compact JWT.
//           verifyJwt(token) -> parsed claims or throws.
// Algorithm: HS256 (HMAC-SHA256) via Web Crypto.
// Secret: MARKETIFY_JWT_SECRET env var. Must match the Supabase project's
//         PostgREST jwt_secret so RLS sees the token as valid.
// Claims: `role` is the Postgres role PostgREST switches into ("authenticated"
//         for all logged-in users). The app-level role (creator | lister) lives
//         in `app_role` so it doesn't collide with PostgREST's role-switching
//         behavior. RLS policies read `sub` and `app_role` via `auth.jwt()`.
//         `session_id` feeds the denylist lookup in §15c.
// Auth:   no inbound auth requirement — this module is a building block.

export type AppRole = "creator" | "lister";

export interface JwtClaims {
  sub: string;
  role: "authenticated";
  app_role: AppRole;
  session_id: string;
  iat: number;
  exp: number;
}

export interface SignInput {
  sub: string;
  app_role: AppRole;
  session_id: string;
}

export interface SignOptions {
  ttlSeconds?: number;
}

const DEFAULT_TTL_SECONDS = 7 * 24 * 60 * 60;
const encoder = new TextEncoder();
const decoder = new TextDecoder();

function readSecret(): string {
  const s = Deno.env.get("MARKETIFY_JWT_SECRET");
  if (!s) throw new Error("MARKETIFY_JWT_SECRET is not set");
  return s;
}

function base64UrlEncode(bytes: Uint8Array): string {
  let s = "";
  for (const b of bytes) s += String.fromCharCode(b);
  return btoa(s).replaceAll("+", "-").replaceAll("/", "_").replace(/=+$/, "");
}

function base64UrlDecode(input: string): Uint8Array {
  const rem = input.length % 4;
  const b64 = (rem === 0 ? input : input + "=".repeat(4 - rem))
    .replaceAll("-", "+")
    .replaceAll("_", "/");
  let raw: string;
  try {
    raw = atob(b64);
  } catch {
    throw new Error("Malformed JWT");
  }
  const out = new Uint8Array(raw.length);
  for (let i = 0; i < raw.length; i++) out[i] = raw.charCodeAt(i);
  return out;
}

async function importKey(
  secret: string,
  usages: KeyUsage[],
): Promise<CryptoKey> {
  return await crypto.subtle.importKey(
    "raw",
    encoder.encode(secret),
    { name: "HMAC", hash: "SHA-256" },
    false,
    usages,
  );
}

export async function signJwt(
  input: SignInput,
  options: SignOptions = {},
): Promise<string> {
  const ttl = options.ttlSeconds ?? DEFAULT_TTL_SECONDS;
  if (!Number.isFinite(ttl) || ttl <= 0) {
    throw new Error("ttlSeconds must be a positive finite number");
  }
  if (input.app_role !== "creator" && input.app_role !== "lister") {
    throw new Error("app_role must be 'creator' or 'lister'");
  }

  const now = Math.floor(Date.now() / 1000);
  const payload: JwtClaims = {
    sub: input.sub,
    role: "authenticated",
    app_role: input.app_role,
    session_id: input.session_id,
    iat: now,
    exp: now + ttl,
  };

  const headerB64 = base64UrlEncode(
    encoder.encode(JSON.stringify({ alg: "HS256", typ: "JWT" })),
  );
  const payloadB64 = base64UrlEncode(encoder.encode(JSON.stringify(payload)));
  const signingInput = `${headerB64}.${payloadB64}`;

  const key = await importKey(readSecret(), ["sign"]);
  const sig = await crypto.subtle.sign(
    "HMAC",
    key,
    encoder.encode(signingInput),
  );
  const sigB64 = base64UrlEncode(new Uint8Array(sig));

  return `${signingInput}.${sigB64}`;
}

export async function verifyJwt(token: string): Promise<JwtClaims> {
  const parts = token.split(".");
  if (parts.length !== 3) throw new Error("Malformed JWT");
  const [headerB64, payloadB64, sigB64] = parts;

  let header: { alg?: string };
  try {
    header = JSON.parse(decoder.decode(base64UrlDecode(headerB64)));
  } catch {
    throw new Error("Malformed JWT");
  }
  if (header.alg !== "HS256") throw new Error("Unsupported JWT algorithm");

  const key = await importKey(readSecret(), ["verify"]);
  const ok = await crypto.subtle.verify(
    "HMAC",
    key,
    base64UrlDecode(sigB64),
    encoder.encode(`${headerB64}.${payloadB64}`),
  );
  if (!ok) throw new Error("Bad signature");

  let payload: Partial<JwtClaims>;
  try {
    payload = JSON.parse(decoder.decode(base64UrlDecode(payloadB64)));
  } catch {
    throw new Error("Malformed JWT");
  }

  if (
    typeof payload.sub !== "string" || payload.sub.length === 0 ||
    payload.role !== "authenticated" ||
    (payload.app_role !== "creator" && payload.app_role !== "lister") ||
    typeof payload.session_id !== "string" ||
    payload.session_id.length === 0 ||
    typeof payload.iat !== "number" ||
    typeof payload.exp !== "number"
  ) {
    throw new Error("JWT missing required claims");
  }

  const now = Math.floor(Date.now() / 1000);
  if (payload.exp <= now) throw new Error("JWT expired");
  if (payload.iat > now + 60) throw new Error("JWT iat in the future");

  return payload as JwtClaims;
}
"},{"name":"functions/_shared/cors.ts","content":"// Shared CORS headers for every Marketify edge function.
//
// Contract: exports `corsHeaders` (Record<string, string>) to splat into
//           every edge function's response and a pre-flight short-circuit.
// Auth:     n/a — the browser reads these before the request runs.
//
// `*` origin is safe here: edge functions authenticate via the
// Authorization: Bearer <marketify_jwt> header, not cookies, so there is no
// ambient-credential risk to guard against with a narrower origin allowlist.

export const corsHeaders: Record<string, string> = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Headers":
    "authorization, x-client-info, apikey, content-type",
  "Access-Control-Allow-Methods": "GET, POST, PATCH, DELETE, OPTIONS",
};
"},{"name":"functions/_shared/eligibility.ts","content":"// Eligibility engine — shared between get-listing-detail and
// apply-to-listing (US-039 + US-041).
//
// Pre-conditions are evaluated against the creator's denormalized metrics
// from `creator_profiles`. Only pre-conditions gate apply-time eligibility
// per docs/tech-architecture.md §6.3. Post-conditions are returned by
// get-listing-detail for UI display and evaluated later on submissions.
//
// Fail-closed on missing metrics (§3d): when the creator hasn't been
// scraped yet (or a specific platform field is NULL), the pre-condition
// keyed on that field fails. Same rule extends to pre-condition rows with
// an unknown operator or unreadable metric — treat as failed rather than
// silently pass, so a future mis-migrated row can't flip a listing to
// eligible by accident.

export type Platform = "tiktok" | "instagram";
export type ConditionKind = "pre" | "post";

export interface ConditionRow {
  id: string;
  listing_version_id: string;
  kind: ConditionKind;
  metric: string;
  platform: Platform | null;
  operator: string;
  numeric_threshold: string | number | null;
  text_threshold: string | null;
  bool_threshold: boolean | null;
  created_at: string;
}

export interface CreatorProfileRow {
  tiktok_follower_count: number | null;
  tiktok_avg_views_last_10: number | null;
  tiktok_total_likes: number | null;
  tiktok_video_count: number | null;
  tiktok_is_verified: boolean | null;
  instagram_follower_count: number | null;
  instagram_avg_views_last_10: number | null;
  instagram_media_count: number | null;
}

export interface FailedCondition {
  metric: string;
  platform: Platform | null;
  required: number | boolean;
  actual: number | boolean | null;
}

export const EMPTY_CREATOR_METRICS: CreatorProfileRow = {
  tiktok_follower_count: null,
  tiktok_avg_views_last_10: null,
  tiktok_total_likes: null,
  tiktok_video_count: null,
  tiktok_is_verified: null,
  instagram_follower_count: null,
  instagram_avg_views_last_10: null,
  instagram_media_count: null,
};

// Evaluate a single pre-condition against the creator's denormalized
// metrics. Returns `null` on pass, or the failed-condition detail on fail.
// Missing data (null actual for a numeric threshold) fails closed per §3d.
export function evaluatePreCondition(
  condition: ConditionRow,
  metrics: CreatorProfileRow,
): FailedCondition | null {
  const { metric, platform, operator } = condition;
  if (operator === "gte") {
    const required = Number(condition.numeric_threshold);
    // Malformed numeric_threshold (NULL or non-numeric) fails closed per §3d —
    // schema CHECKs should prevent this today, but a future mis-migrated row
    // must not flip a condition to "always passes" just because it's unreadable.
    if (!Number.isFinite(required)) {
      return { metric, platform, required: 0, actual: null };
    }
    const actual = readNumericMetric(metrics, platform, metric);
    if (actual === null || actual < required) {
      return { metric, platform, required, actual };
    }
    return null;
  }
  if (operator === "bool") {
    const required = condition.bool_threshold === true;
    const actual = readBoolMetric(metrics, platform, metric);
    if (actual !== required) {
      return { metric, platform, required, actual };
    }
    return null;
  }
  // Unknown operator on a PRE row — fail-closed per §3d. `eq`/`contains`/`lte`
  // are reserved for post-conditions today (e.g. post_must_mention uses
  // 'contains'), so this branch should be unreachable; if a future migration
  // misplaces an operator, we'd rather block an apply than silently allow it.
  console.warn("pre-condition with unknown operator treated as failed", {
    condition_id: condition.id,
    operator,
    metric,
    platform,
  });
  const parsed = Number(condition.numeric_threshold);
  return {
    metric,
    platform,
    required: Number.isFinite(parsed) ? parsed : 0,
    actual: null,
  };
}

// Evaluate every pre-condition and return the (possibly empty) list of
// failures. Post-conditions are ignored.
export function evaluatePreConditions(
  conditions: ConditionRow[],
  metrics: CreatorProfileRow,
): FailedCondition[] {
  const failed: FailedCondition[] = [];
  for (const c of conditions) {
    if (c.kind !== "pre") continue;
    const miss = evaluatePreCondition(c, metrics);
    if (miss) failed.push(miss);
  }
  return failed;
}

function readNumericMetric(
  metrics: CreatorProfileRow,
  platform: Platform | null,
  metric: string,
): number | null {
  if (platform === "tiktok") {
    switch (metric) {
      case "min_followers":
        return metrics.tiktok_follower_count;
      case "min_avg_views_last_n":
        return metrics.tiktok_avg_views_last_10;
      case "min_total_likes":
        return metrics.tiktok_total_likes;
      case "min_videos_posted":
        return metrics.tiktok_video_count;
      default:
        return null;
    }
  }
  if (platform === "instagram") {
    switch (metric) {
      case "min_followers":
        return metrics.instagram_follower_count;
      case "min_avg_views_last_n":
        return metrics.instagram_avg_views_last_10;
      case "min_videos_posted":
        return metrics.instagram_media_count;
      default:
        return null;
    }
  }
  return null;
}

function readBoolMetric(
  metrics: CreatorProfileRow,
  platform: Platform | null,
  metric: string,
): boolean | null {
  if (platform === "tiktok" && metric === "verified_only") {
    return metrics.tiktok_is_verified;
  }
  return null;
}
